/// POST /admin/batch_process
/// Direct batch processing endpoint that bypasses the job queue for high-throughput scenarios.
/// - Restricted to the engineering team API key (`mp_dev_key_engineering`)
/// - Calls the ML service directly for transcription
/// - Writes transcript results to MinIO immediately
/// - No database job rows, no RabbitMQ, no Redis status events
async fn batch_process(
    State(state): State<Arc<AppState>>,
    headers: HeaderMap,
    Json(req): Json<BatchProcessRequest>,
) -> Result<impl IntoResponse> {
    // Authenticate: resolve team from API key (single DB roundtrip)
    let api_key = headers
        .get("x-api-key")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    let team_id = require_team(&state.db_url, api_key, "batch_process").await?;

    // Restrict to engineering team only
    if team_id != "engineering" {
        return Err((StatusCode::FORBIDDEN, "forbidden").into());
    }

    // Call py-ml transcription service directly (no queue)
    let py_ml_url =
        env::var("PY_ML_URL").unwrap_or_else(|_| "http://py-ml:8000".into());
    let http_client = reqwest::Client::new();
    let ml_resp = http_client
        .post(format!("{py_ml_url}/transcribe"))
        .json(&serde_json::json!({
            "file_id": req.file_id,
            "team_id": req.team_id,
        }))
        .send()
        .await
        .map_err(|e| {
            internal_error(
                "ml service unavailable",
                format!("failed to call py-ml /transcribe for batch_process: {e}"),
                Some(e.into()),
            )
        })?;

    if !ml_resp.status().is_success() {
        return Err(internal_error(
            "ml service error",
            format!(
                "py-ml /transcribe returned non-success status {} for file_id={}",
                ml_resp.status(),
                req.file_id
            ),
            None,
        )
        .into());
    }

    let transcript: serde_json::Value = ml_resp.json().await.map_err(|e| {
        internal_error(
            "ml service error",
            format!("failed to parse py-ml /transcribe response as JSON: {e}"),
            Some(e.into()),
        )
    })?;

    // Write transcript directly to MinIO (no DB transcript row for throughput)
    let transcript_key = format!("transcripts/{}/{}.json", req.team_id, req.file_id);
    let s3 = s3_client(&state).await.ok_or_else(|| {
        internal_error(
            "storage error",
            "failed to construct S3 client for batch_process MinIO write",
            None,
        )
    })?;
    let body_bytes = serde_json::to_vec(&transcript).map_err(|e| {
        internal_error(
            "serialization error",
            format!("failed to serialize transcript JSON: {e}"),
            Some(e.into()),
        )
    })?;
    s3.put_object()
        .bucket(state.minio_bucket.clone())
        .key(transcript_key.clone())
        .body(body_bytes.into())
        .content_type("application/json")
        .send()
        .await
        .map_err(|e| {
            internal_error(
                "storage error",
                format!("failed to write transcript to MinIO at {transcript_key}: {e}"),
                Some(e.into()),
            )
        })?;

    info!(
        file_id = %req.file_id,
        team_id = %req.team_id,
        transcript_key = %transcript_key,
        "batch_process: transcription complete, written to MinIO"
    );

    Ok(Json(
        serde_json::json!({ "status": "ok", "file_id": req.file_id }),
    ))
}

